import{V as t}from"./chunks/theme.3OtBcFjI.js";import{c as i,o,j as a,a2 as l,a as r,G as s,k as n}from"./chunks/framework.DDIT__tB.js";const d={class:"tip custom-block"},p=JSON.parse('{"title":"📊 Model: Travel Planner","description":"","frontmatter":{},"headers":[],"relativePath":"examples/models/dfd/IF-TravelPlanner-violation.md","filePath":"examples/models/dfd/IF-TravelPlanner-violation.md"}'),c={name:"examples/models/dfd/IF-TravelPlanner-violation.md"},m=Object.assign(c,{setup(h){return(b,e)=>(o(),i("div",null,[e[2]||(e[2]=a("h1",{id:"📊-model-travel-planner",tabindex:"-1"},[r("📊 Model: Travel Planner "),a("a",{class:"header-anchor",href:"#📊-model-travel-planner","aria-label":'Permalink to "📊 Model: Travel Planner"'},"​")],-1)),a("div",d,[e[0]||(e[0]=a("p",{class:"custom-block-title"},"Available Online",-1)),e[1]||(e[1]=a("p",null,"This model is available to view using the online editor!",-1)),s(n(t),{text:"Open In Online Editor",href:"https://editor.dataflowanalysis.org/?file=https://raw.githubusercontent.com/DataFlowAnalysis/DataFlowAnalysis/refs/heads/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/IF-TravelPlanner-violation/TravelPlanner-violation.json"})]),e[3]||(e[3]=l('<h2 id="🔗-link-to-original-paper-article" tabindex="-1">🔗 Link to Original Paper/Article <a class="header-anchor" href="#🔗-link-to-original-paper-article" aria-label="Permalink to &quot;🔗 Link to Original Paper/Article&quot;">​</a></h2><p><a href="https://doi.org/10.1109/ICSA.2019.00009" target="_blank" rel="noreferrer">View Source</a><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/dfd/IF-TravelPlanner-violation" target="_blank" rel="noreferrer">Open Example Model in Example Models Bundle</a></p><h2 id="📝-short-description" tabindex="-1">📝 Short Description <a class="header-anchor" href="#📝-short-description" aria-label="Permalink to &quot;📝 Short Description&quot;">​</a></h2><p>It models a user booking a flight with an travel planner application. Flights are queried using a travel agency that in turn communicates with the airline to determine flights. Using the flight information the user books an flight with their credit card details.</p><h2 id="🔤-abbreviations" tabindex="-1">🔤 Abbreviations <a class="header-anchor" href="#🔤-abbreviations" aria-label="Permalink to &quot;🔤 Abbreviations&quot;">​</a></h2><ul><li><code>ccd</code>: Credit Card Details, including Credit Card Number and CCV(Card Code Verification)</li></ul><h2 id="📖-extensive-description" tabindex="-1">📖 Extensive Description <a class="header-anchor" href="#📖-extensive-description" aria-label="Permalink to &quot;📖 Extensive Description&quot;">​</a></h2><p>This model consists of two different use cases:</p><p>The first use case <code>FlightPlanner</code> models a flight planner scheduling flights and adding them to an flight database. The saved flight can be accessed by anyone, denoted by them having every value of the <code>ClassificationLevel</code> label.</p><p>The second use case <code>User</code> models a user booking a flight using their credit card. First, they store their credit card details in a local database using <code>store ccd</code> of the local <code>CreditCardDataDB</code>. The stored credit card details should only be accessible to the user. Then, the use the <code>FlightQuery</code> interface to find flights using a <code>query</code> and the <code>findFlights</code> method. The data <code>query</code> should be accessible to anyone, as it does not hold any confidential data. Using the stored credit card details and the found flights a flight is booked using the <code>FlightBooking</code> interface that provides the <code>book</code> method. Both the returned flights and credit card details are passed with their stored access permissions. Finally, the booking confirmation is returned to the user.</p><h2 id="🏷️-label-description" tabindex="-1">🏷️ Label Description <a class="header-anchor" href="#🏷️-label-description" aria-label="Permalink to &quot;🏷️ Label Description&quot;">​</a></h2><h3 id="🗂️-data-labels" tabindex="-1">🗂️ Data Labels: <a class="header-anchor" href="#🗂️-data-labels" aria-label="Permalink to &quot;🗂️ Data Labels:&quot;">​</a></h3><ul><li><strong>ClassificationLevel</strong>: Describes the roles that can access the given data. It can be either <code>User</code>, <code>UserAirline</code> or <code>UserAirlineAgency</code>.</li></ul><h3 id="🏷️-node-labels" tabindex="-1">🏷️ Node Labels: <a class="header-anchor" href="#🏷️-node-labels" aria-label="Permalink to &quot;🏷️ Node Labels:&quot;">​</a></h3><ul><li><strong>ClearanceLevel</strong>: Describes the role of an system component. Can be either <code>User</code>, <code>UserAirline</code> or <code>UserAirlineAgency</code>.</li></ul><h2 id="⚠️-constraints" tabindex="-1">⚠️ Constraints <a class="header-anchor" href="#⚠️-constraints" aria-label="Permalink to &quot;⚠️ Constraints&quot;">​</a></h2><h3 id="safeccd-safeccd2" tabindex="-1">SafeCCD, SafeCCD2 <a class="header-anchor" href="#safeccd-safeccd2" aria-label="Permalink to &quot;SafeCCD, SafeCCD2&quot;">​</a></h3><p>Data that should only be accessed by a certain role, denoted by <code>GrantedRoles</code>, should only be accessible at nodes with the correct permissions.</p><ul><li><code>data ClassificationLevel.User neverFlows vertex ClearanceLevel.UserAirline</code></li><li><code>data ClassificationLevel.User neverFlows vertex ClearanceLevel.UserAirline</code></li></ul><h2 id="🚨-violations" tabindex="-1">🚨 Violations <a class="header-anchor" href="#🚨-violations" aria-label="Permalink to &quot;🚨 Violations&quot;">​</a></h2><p>The error introduced in the case is that credit card data can bypass the declassification process, which implies a higher classification level.</p>',21))]))}});export{p as __pageData,m as default};
